const loopProgress = (
  timeline: number,
  enterStart: number,
  enterEnd: number,
  exitStart = 790,
  exitEnd = 900,
) => {
  const enter = interpolate(timeline, [enterStart, enterEnd], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.inOut(Easing.cubic),
  });
  const exit = interpolate(timeline, [exitStart, exitEnd], [1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.inOut(Easing.cubic),
  });
  return Math.min(enter, exit);
};

const pop = (progress: number) =>
  progress + Math.sin(progress * Math.PI) * 0.075;

const valueAt = (data: readonly number[], progress: number) => {
  const p = Math.max(0, Math.min(0.99999, progress)) * (data.length - 1);
  const index = Math.floor(p);
  const local = p - index;
  return data[index] + (data[Math.min(index + 1, data.length - 1)] - data[index]) * local;
};

const sampledPoint = (
  points: readonly (readonly [number, number])[],
  progress: number,
) => {
  const scaled = Math.max(0, Math.min(0.99999, progress)) * (points.length - 1);
  const index = Math.floor(scaled);
  const local = scaled - index;
  const next = points[Math.min(index + 1, points.length - 1)];
  return {
    x: points[index][0] + (next[0] - points[index][0]) * local,
    y: points[index][1] + (next[1] - points[index][1]) * local,
  };
};

const money = (value: number) => `$${value.toFixed(1)}M`;

const Card: React.FC<{
  x: number;
  y: number;
  width: number;
  height: number;
  reveal?: number;
  depth?: number;
  float?: number;
  dark?: boolean;
  children: React.ReactNode;
}> = ({x, y, width, height, reveal = 1, depth = 0, float = 0, dark = false, children}) => (
  <div
    data-safe-object="true"
    style={{
      position: 'absolute',
      left: x,
      top: y,
      width,
      height,
      overflow: 'hidden',
      borderRadius: 21,
      background: dark
        ? 'linear-gradient(145deg, rgba(13,47,58,.99), rgba(7,34,43,.99))'
        : 'rgba(255,255,255,.88)',
      border: dark ? '1px solid rgba(205,244,239,.12)' : '1px solid rgba(255,255,255,.96)',
      boxShadow: dark
        ? '0 22px 45px rgba(15,51,57,.2), inset 0 1px 0 rgba(255,255,255,.05)'
        : '0 16px 34px rgba(45,76,77,.1), inset 0 1px 0 rgba(255,255,255,.92)',
      opacity: 0.82 + reveal * 0.18,
      transform: `translate3d(0, ${(1 - reveal) * 9 + float}px, ${depth}px) scale(${0.987 + reveal * 0.013})`,
      transformStyle: 'preserve-3d',
      backfaceVisibility: 'hidden',
      willChange: 'transform, opacity',
    }}
  >
    <div style={{position: 'absolute', inset: 0, pointerEvents: 'none', background: dark ? 'linear-gradient(135deg, rgba(255,255,255,.035), transparent 35%, transparent)' : 'linear-gradient(135deg, rgba(255,255,255,.8), transparent 30%, rgba(22,197,199,.018))'}}/>
    {children}
  </div>
);

