const Dashboard: React.FC<{timeline: number; phase: number}> = ({timeline, phase}) => (
  <div style={{position: 'relative', width: 1660, height: 850, overflow: 'hidden', borderRadius: 31, background: 'linear-gradient(145deg, rgba(248,251,250,.98), rgba(239,246,244,.98))', border: '1px solid rgba(255,255,255,.95)', boxShadow: '0 42px 85px rgba(55,80,78,.19), inset 0 1px 0 rgba(255,255,255,1)', transformStyle: 'preserve-3d'}}>
    <div style={{position: 'absolute', inset: 0, opacity: .16, backgroundImage: 'linear-gradient(rgba(74,124,124,.08) 1px, transparent 1px), linear-gradient(90deg, rgba(74,124,124,.08) 1px, transparent 1px)', backgroundSize: '46px 46px'}}/>
    <div style={{position: 'absolute', left: -130, top: -190, width: 760, height: 620, borderRadius: '50%', background: 'radial-gradient(circle, rgba(119,103,231,.08), transparent 69%)'}}/>
    <div style={{position: 'absolute', right: -190, bottom: -190, width: 740, height: 610, borderRadius: '50%', background: 'radial-gradient(circle, rgba(22,197,199,.1), transparent 70%)'}}/>
    <Header timeline={timeline} phase={phase}/>
    <WorldMap timeline={timeline} phase={phase}/>
    <RegionPanel timeline={timeline} phase={phase}/>
    <CashRiver timeline={timeline} phase={phase}/>
  </div>
);

export const Motion: React.FC = () => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const timeline = (frame / durationInFrames) * 900;
  const phase = (frame / durationInFrames) * Math.PI * 2;
  const boardReveal = loopProgress(timeline, 0, 76, 838, 900);
  const cameraX = Math.sin(phase) * 28 + Math.sin(phase * 2 + .6) * 6;
  const cameraY = Math.sin(phase * 2 - .35) * 10 + Math.sin(phase + .8) * 4;
  const cameraScale = 1.006 + Math.sin(phase - .5) * .009 + Math.sin(phase * 2 + .25) * .003;
  const rotateX = Math.sin(phase + .7) * .32 + Math.sin(phase * 2) * .08;
  const rotateY = Math.cos(phase) * .52 + Math.sin(phase * 2 + .4) * .12;
  const rotateZ = Math.sin(phase - .4) * .055;
  const sweep = loopProgress(timeline, 560, 720, 748, 812);
  const sweepOpacity = Math.sin(sweep * Math.PI) * .15;
  const dots = Array.from({length: 30}, (_, index) => ({
    x: 40 + ((index * 173 + 91) % 1840),
    y: 30 + ((index * 107 + 53) % 1020),
    size: 1 + (index % 3) * .55,
  }));
  return (
    <AbsoluteFill style={{overflow: 'hidden', background: 'radial-gradient(circle at 72% 18%, #f9fcfb 0%, #eaf2f0 45%, #dfe9e7 100%)', fontFamily: 'Arial, Helvetica, sans-serif'}}>
      <div style={{position: 'absolute', inset: 0, opacity: .25, backgroundImage: 'linear-gradient(rgba(50,105,104,.08) 1px, transparent 1px), linear-gradient(90deg, rgba(50,105,104,.08) 1px, transparent 1px)', backgroundSize: '76px 76px', transform: `translate(${Math.sin(phase) * -6}px, ${Math.cos(phase) * 5}px)`}}/>
      <div style={{position: 'absolute', left: 950 + Math.sin(phase) * 110, top: -180 + Math.cos(phase) * 45, width: 880, height: 700, borderRadius: '50%', background: 'radial-gradient(circle, rgba(22,197,199,.13), rgba(22,197,199,.025) 42%, transparent 70%)', filter: 'blur(20px)'}}/>
      <div style={{position: 'absolute', left: -170 + Math.cos(phase) * 75, bottom: -190 + Math.sin(phase) * 35, width: 760, height: 600, borderRadius: '50%', background: 'radial-gradient(circle, rgba(119,103,231,.1), transparent 70%)', filter: 'blur(24px)'}}/>
      {dots.map((dot, index) => <div key={index} style={{position: 'absolute', left: dot.x + Math.sin(phase * 1.5 + index) * 4, top: dot.y + Math.cos(phase * 1.2 + index) * 3, width: dot.size, height: dot.size, borderRadius: '50%', background: index % 6 === 0 ? C.gold : C.cyan, opacity: .08 + (Math.sin(phase * 2 + index) + 1) * .035}}/>)}
      <div data-safe-object="board" style={{position: 'absolute', left: 130, top: 115, width: 1660, height: 850, transformOrigin: '50% 50%', transformStyle: 'preserve-3d', opacity: .84 + boardReveal * .16, willChange: 'transform, opacity', transform: `perspective(3600px) translate3d(${cameraX}px, ${cameraY}px, 0) rotateX(${rotateX}deg) rotateY(${rotateY}deg) rotateZ(${rotateZ}deg) scale(${cameraScale * (.979 + boardReveal * .021)})`}}>
        <Dashboard timeline={timeline} phase={phase}/>
        <div style={{position: 'absolute', inset: 0, overflow: 'hidden', borderRadius: 31, pointerEvents: 'none', transform: 'translateZ(30px)'}}><div style={{position: 'absolute', left: -260 + sweep * 2210, top: -170, width: 110, height: 1200, transform: 'rotate(14deg)', background: 'linear-gradient(90deg, transparent, rgba(255,255,255,.95), transparent)', filter: 'blur(7px)', opacity: sweepOpacity}}/></div>
      </div>
      <div style={{position: 'absolute', inset: 0, pointerEvents: 'none', opacity: .055, backgroundImage: 'radial-gradient(circle at 1px 1px, rgba(35,83,80,.42) .55px, transparent .75px)', backgroundSize: '6px 6px', mixBlendMode: 'multiply'}}/>
      <div style={{position: 'absolute', inset: 0, pointerEvents: 'none', background: 'radial-gradient(ellipse at center, transparent 64%, rgba(43,68,65,.12) 100%)'}}/>
    </AbsoluteFill>
  );
};
